    for (int i = 0; i < n; i++) {
        arr[i] = true;
    }

    for (int i = 2; i < sqrt(n); i++) {
        if (arr[i]) {
            for (int j = i * i; j < n; j += i) {
                arr[j] = false;
            }
        }
